import React from "react";

const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);
const round = (x) => (x == null ? null : Math.round(x));

// Normalize probability-of-precipitation from either 0..1 or 0..100 -> 0..1
function normPop(p) {
  if (p == null || Number.isNaN(Number(p))) return null;
  let x = Number(p);
  if (x > 1) x = x / 100; // treat 42 or 100 as 0.42 or 1.0
  return Math.max(0, Math.min(1, x)); // clamp to [0,1]
}
function fmtPop(p) {
  const x = normPop(p);
  if (x == null) return "—";
  return `${Math.round(x * 100)}%`;
}

// ---- NEW: safely stringify weather fields of any shape ----
function safeWeatherLabel(w) {
  if (w == null) return "—";

  // If daily item is like { weather: [{main, description}, ...] }
  if (Array.isArray(w) && w.length) {
    const first = w[0];
    if (typeof first === "string") return first;
    if (first && typeof first === "object") return first.description || first.main || "—";
    return "—";
  }

  // If daily item is like { weather: { main, description } }
  if (typeof w === "object") {
    return w.description || w.main || "—";
  }

  // string or number
  return String(w);
}

export default function Forecast({ hourly = [], daily = [], daily16 = [], unit = "metric" }) {
  const fmtT = (c) => (unit === "imperial" ? round(toF(c)) : round(c));

  const hasDaily = Array.isArray(daily) && daily.length > 0;
  const hasExt = Array.isArray(daily16) && daily16.length > 0;

  return (
    <div className="space-y-6 text-white">
      {/* Hourly */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Next Hours</h2>
        <div className="flex gap-3 overflow-x-auto pb-2">
          {(hourly ?? []).map((h) => (
            <div key={h.dt} className="shrink-0 rounded-2xl px-3 py-2 bg-black/40 backdrop-blur">
              <div className="text-sm">
                {new Date((h.dt ?? Date.now() / 1000) * 1000).toLocaleTimeString([], {
                  hour: "numeric",
                })}
              </div>
              <div className="text-center text-2xl">{fmtT(h.temp)}°</div>
              <div className="text-xs opacity-75">{fmtPop(h.pop)}</div>
            </div>
          ))}
          {!hourly?.length && <div className="opacity-70 text-sm">No hourly data.</div>}
        </div>
      </section>

      {/* Daily */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Daily</h2>
        <div className="flex flex-col gap-2">
          {hasDaily ? (
            daily.map((d) => {
              const label = safeWeatherLabel(d.weather);
              return (
                <div
                  key={d.dt}
                  className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between"
                >
                  <div className="w-36">
                    <div className="font-medium">
                      {new Date((d.dt ?? Date.now() / 1000) * 1000).toLocaleDateString(
                        undefined,
                        { weekday: "short" }
                      )}
                    </div>
                    <div className="text-xs opacity-80 truncate">{label}</div>
                  </div>
                  <div className="flex-1 text-right">
                    {fmtT(d.min)}° / <strong>{fmtT(d.max)}°</strong>
                  </div>
                  <div className="w-20 text-right text-sm opacity-75">{fmtPop(d.pop)}</div>
                </div>
              );
            })
          ) : (
            <div className="opacity-70 text-sm">No daily data.</div>
          )}
        </div>
      </section>

      {/* Extended (16‑day) */}
      <section>
        <h2 className="text-lg font-semibold mb-2">16‑Day Forecast</h2>
        <div className="flex flex-col gap-2">
          {hasExt ? (
            daily16.map((d, i) => {
              const min = d?.temp?.min ?? d.min;
              const max = d?.temp?.max ?? d.max;
              const label = safeWeatherLabel(d.weather ?? d.description);
              return (
                <div
                  key={`${d.dt ?? i}-${i}`}
                  className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between"
                >
                  <div className="w-44 pr-2">
                    <div className="font-medium">
                      {new Date((d.dt ?? Date.now() / 1000) * 1000).toLocaleDateString(
                        undefined,
                        { weekday: "short", month: "short", day: "numeric" }
                      )}
                    </div>
                    <div className="text-xs opacity-80 truncate">{label}</div>
                  </div>
                  <div className="flex-1 text-right">
                    {fmtT(min)}° / <strong>{fmtT(max)}°</strong>
                  </div>
                  <div className="w-20 text-right text-sm opacity-75">{fmtPop(d.pop)}</div>
                </div>
              );
            })
          ) : (
            <div className="opacity-70 text-sm">No extended forecast available.</div>
          )}
        </div>
      </section>
    </div>
  );
}
